  ('police-3218f787-moex-00077', 'police-3218f787', 'police-3218f787-moex-113-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '有關憲法教育文化之基本國策規定，下列敘述何者正確？', '["國家得制定出版法，針對公私立文化機構之出版品內容實施檢查，並對有礙於國民身心道 德健康發展之出版品，禁止其出版", "依憲法第164條規定，市、縣政府所編列之教、科、文經費，均不得低於其預算總額百分 之二十五", "國家得制定學位授予法規範私立大學所授予之各種學位，並不至於因此侵害私人興學之自由", "國家應對6歲至15歲之學齡兒童提供免納學費之基本教育"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
