  ('police-3218f787-moex-00079', 'police-3218f787', 'police-3218f787-moex-113-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '有關非現役軍人不受軍事審判之規定，係為保障下列何基本權？', '["言論自由", "居住自由", "遷徙自由", "人身自由"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00080', 'police-3218f787', 'police-3218f787-moex-113-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依司法院釋字第509號解釋意旨，關於誹謗性言論，下列敘述何者正確？', '["不受憲法言論自由之保障", "行為人必須自行證明其言論內容確屬真實，始能免於刑責", "依行為人所提證據資料，認為其有相當理由確信言論內容為真實者，即不構成誹謗罪", "行為人言論內容如經法院調查發現並非真實，即構成誹謗罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00081', 'police-3218f787', 'police-3218f787-moex-113-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依司法院大法官解釋意旨，關於大學自治，下列敘述何者錯誤？', '["大學自治為憲法第11條講學自由之保障範圍", "大學對於教學、研究與學習之事項，享有自治權", "大學自治事項範圍包括內部組織、課程設計、考試規則、畢業條件及入學資格", "國家對於大學之監督，應以法律為之，為健全學生體格，得規定大學應設體育室"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00082', 'police-3218f787', 'police-3218f787-moex-113-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '下列何種基本權利與秘密通訊自由最具有密不可分之關係？', '["平等權", "財產權", "隱私權", "參政權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00083', 'police-3218f787', 'police-3218f787-moex-113-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依司法院大法官解釋，下列何者並未牴觸憲法第13條宗教自由之保障？', '["法律規定某特定宗教為國教", "法律規定人民不得因宗教信仰而拒服兵役", "法律規定信仰某特定宗教之人民得享有減稅優惠", "法律規定不信仰某特定宗教之人民得領取生活津貼"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00084', 'police-3218f787', 'police-3218f787-moex-113-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '關於憲法第7條男女平等，司法院大法官曾作過的違憲宣告解釋，不包括下列何者？', '["舊民法第 1089 條關於父母對於未成年子女權利之行使意思不一致時，由父行使之規定部 分，違憲", "舊民法第1002條「妻以夫之住所為住所」之規定，違憲", "民法夫妻財產制修正後對修正前已發生之夫妻聯合財產，規定仍由夫繼續享有之部分，違憲", "陸軍官校基於其歷史傳統而以性別為錄取學生之標準，違憲"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00085', 'police-3218f787', 'police-3218f787-moex-113-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '地價稅法關於免徵土地增值稅之規定，僅就依都市計畫法指定之公共設施保留地免徵其土地 增值稅，而非都市土地經編定為交通用地且依法核定為公共用地者，則不予免徵。司法院大 法官解釋認定上開規定違反平等權之理由為：', '["此差別待遇之手段與立法目的之達成間欠缺合理關聯性", "此差別待遇未符合比例原則", "以與事物本質無關之要素，作為差別待遇之基準", "未將與事物本質有關聯之要素，列為差別待遇之基準"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:09+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
